.legend-icon.freeswap-horizontal-tile {
    border: 2px solid var(--tile-freeswap-border);
    position: relative;
}

.legend-icon.freeswap-horizontal-tile::after {
    content: "";
    position: absolute;
    top: -2px;
    right: -2px;
    width: 14px;
    height: 14px;
    border-radius: 35%;
    background-color: var(--tile-freeswap-badge-bg);
    background-image: url("assets/arrow-horizontal.svg");
    background-size: 75%;
    background-position: center;
    background-repeat: no-repeat;
}

.grid-row {
    display: flex;
    gap: 2px;
    margin-bottom: 2px;
}

.example-tile {
    width: 30px;
    height: 30px;
    background: var(--tile-2-bg);
    color: var(--tile-2-color);
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 20%;
    font-family: Nunito;
    font-weight: 900;
    font-size: 14px;
    box-shadow: 0 -3px 0 0 rgba(0, 0, 0, 0.25) inset;
    padding-bottom: 2px;
}

.example-tile.target-highlight {
    box-shadow:
        0px 0px 0px 3px #aee96b,
        0 -3px 0 0 rgba(0, 0, 0, 0.25) inset;
    z-index: 2;
}

.example-tile.result {
    width: 42px;
    height: 42px;
    font-size: 18px;
}

.example-tile.highlight {
    background: var(--tile-3-bg);
    color: var(--tile-3-color);
    box-shadow: 0 -3px 0 0 rgba(0, 0, 0, 0.25) inset;
}

.example-tile.highlight.double {
    background: var(--tile-4-bg);
    color: var(--tile-4-color);
    box-shadow: 0 -3px 0 0 rgba(0, 0, 0, 0.25) inset;
}

.grid-row span:empty {
    width: 30px;
    height: 30px;
    display: inline-block;
}

.example-result {
    display: inline-block;
    margin: 10px;
}

.arrow {
    font-size: 28px;
    color: #aee96b;
    font-weight: bold;
    margin: 0 10px;
    padding-bottom: 5px;
}

/* Power-up info styling */
.powerup-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
    margin-top: 12px;
}

.powerup-item {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 8px;
    background: rgba(255, 255, 255, 0.05);
    border-radius: 8px;
}

.powerup-icon {
    font-size: 24px;
    width: 32px;
    text-align: center;
}

.powerup-info {
    flex: 1;
    font-size: 14px;
    line-height: 1.3;
}

.powerup-info strong {
    color: rgba(255, 255, 255, 0.9);
}

